import { concatenarTabelas, intervaloCompetencias, TCelula, TTabela } from "@cecalc/utils";
import type { IDadosPlenus, ITabelasPlenus, TResumoPlenus } from "./tipos";

export default function gerarTabelas(dados: IDadosPlenus): ITabelasPlenus {
  const info: TTabela<TCelula> = [
    ['Segurado:', (dados.beneficio.segurado ?? '')], 
    ['Data de Nascimento:', (dados.beneficio.dataNascimento ?? '')],
    ['Idade:', (dados.beneficio.idade ?? '')],
    ['NB:', (dados.beneficio.nb ?? '')],
    ['Espécie:', (dados.beneficio.especie ?? '')],
    ['Calcular abono (dado calculado, não constante do Plenus):', (dados.beneficio.calcularAbono ?? '')],
    ['DER:', (dados.beneficio.der ?? '')],
    ['DIB:', (dados.beneficio.dib ?? '')],
    ['DDB:', (dados.beneficio.ddb ?? '')],
    ['DIP:', (dados.beneficio.dip ?? '')],
    ['DCB:', (dados.beneficio.dcb ?? '')],
    ['Expectativa de sobrevida:', (dados.beneficio.expectativaSobrevida ?? '')],
    ['Fator Previdenciário:', (dados.beneficio.fatorPrevidenciario ?? '')],
    ['Coeficiente:', (dados.beneficio.coeficiente ?? '')],
    ['Salário-de-benefício:', (dados.beneficio.salarioBeneficio ?? '')],
    ['RMI:', (dados.beneficio.rmi ?? '')],
    ['RMA:', (dados.beneficio.rma ?? '')],
    ['Índice Teto:', (dados.beneficio.indiceTeto ?? '')],
    ['TC Anos:', (dados.beneficio.TCAnos ?? '')],
    ['TCMeses:', (dados.beneficio.TCMeses ?? '')],
    ['TCDias:', (dados.beneficio.TCDias ?? '')]
  ];

  const salarios: TTabela<TCelula> = []
  let novaPagina: TTabela<TCelula> = []
  let competenciaInicial, competenciaFinal

  if (Array.isArray(dados.salarios) && dados.salarios.length > 0) {
    // No Plenus, as competências ficam em ordem descrescente.
    competenciaFinal = dados.salarios[0].competencia.competencia(); 
    competenciaInicial = dados.salarios[dados.salarios.length - 1].competencia.competencia();
    
    const competencias = intervaloCompetencias(competenciaInicial, competenciaFinal);
    
    novaPagina.push(['Seq', 'Competência', 'Valor Original', 'Índice', 'Valor Corrigido', 'Desconsiderado']);
    
    competencias.forEach(competencia => {
      let salario;
      for (let i = 0; i < dados.salarios.length; i++) {
        const item = dados.salarios[i]
        if (item.competencia.igualA(competencia)) {
          salario = item
          break;
        }
      }
      if (salario) {
        salarios.push([salario.valorOriginal])
        novaPagina.push([salario.seq, competencia, salario.valorOriginal, salario.indice, salario.valorCorrigido, salario.desconsiderado])
      } else {
        salarios.push([0])
        novaPagina.push(['', competencia, '', '', '', ''])
      }
    });
  }

  novaPagina = concatenarTabelas(info, novaPagina)

  const resumo: TResumoPlenus = [
    ['Segurado(a):', dados.beneficio.segurado],
    ['NB:', dados.beneficio.nb],
    ['Dados:', `${dados.salarios.length} salários encontrados`]
  ]

  return { resumo, salarios, novaPagina, competenciaInicial, competenciaFinal }
}
