import { CnisCompleto, CnisVinculos, MeuINSS, Plenus, Hiscre, PJe, SisJef, TempoContribuicao, IModulo, IResultadoAnalisador, IOpcaoAnalisador } from './modules'

export class AnalisadorDeTexto {
  private modulos: IModulo[] = [SisJef, PJe, Hiscre, MeuINSS, CnisCompleto, CnisVinculos, Plenus, TempoContribuicao]
  private resultado?: IResultadoAnalisador
  private _identificado = false

  constructor(texto: string) {
    for (let i = 0; i < this.modulos.length; i++) {
      if (this.modulos[i].testar(texto)) {
        const Analisador = this.modulos[i]
        this.resultado = new Analisador().analisar(texto)
        this._identificado = (this.resultado !== undefined && this.resultado !== null)
        break;
      }      
    }
  }

  public get identificado(): boolean {
    return this._identificado
  }

  public obterNome(): string {
    return this.resultado ? this.resultado.nome : ''
  }

  public obterResumo(): string[][] {
    return this.resultado ? this.resultado.resumo : []
  }

  public obterOpcoes(intervalos: string[]): IOpcaoAnalisador[] {
    if (this.resultado) {
      return this.resultado.opcoes.filter(opcao => {
        return opcao.parametros.some(parametro => {
          if (parametro.intervalo.length === 0) return true
          if (Array.isArray(parametro.intervalo)) {
            return parametro.intervalo.some(intervalo => intervalos.includes(intervalo))
          }
          return intervalos.includes(parametro.intervalo)
        })
      })
    }
    return []
  }
}
