import { concatenarTabelas, TCelula, TTabela } from "@cecalc/utils";
import type { IDadosTc, ITabelasTc, TResumoTc } from "./tipos";

function analisarDescricaoAtividade(descricao: string): string[] {
  descricao = descricao.replace(/[()]/g, '');
  const [ empregador, natureza ] = descricao.split('-')
  return [empregador?.trim() || '', natureza?.trim() || ''];
}

export default function gerarTabelas(dados: IDadosTc[]): ITabelasTc {

  const periodos: TTabela<TCelula> = dados.map(periodo => {
    const descricao = analisarDescricaoAtividade(periodo.descricao || '')
    return [descricao[0], descricao[1], periodo.dataInicial, periodo.dataFinal];
  });

  const cabecalho = [['Empregador', 'Natureza', 'Data Inicial', 'Data Final']]
  const novaPagina: TTabela<TCelula> = concatenarTabelas(cabecalho, periodos)

  const resumo: TResumoTc = [
    ['Dados:', `${dados.length} períodos encontrados`]
  ]

  return { resumo, periodos, novaPagina }
}
